m['is_active']) ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-600' ?>"><?= !empty($item['is_active']) ? 'Ativa' : 'Inativa' ?></span></td><td class="py-3 pr-4"><div class="flex gap-3"><a class="font-semibold text-teal-700" href="index.php?route=admin/food-categories&id=<?= h($item['id']) ?>">Editar</a><form method="post" action="index.php?route=admin/food-category-delete" onsubmit="return confirm('Remover ou inativar esta categoria?');"><input type="hidden" name="_csrf" value="<?= h(csrf_token()) ?>"><input type="hidden" name="id" value="<?= h($item['id']) ?>"><button class="font-semibold text-red-700" type="submit"><?= !empty($item['is_active']) ? 'Excluir' : 'Remover' ?></button></form></div></td></tr><?php endforeach; ?></tbody></table><?php if (!$foodCategories): ?><div class="text-slate-500">Nenhuma categoria cadastrada ainda.</div><?php endif; ?></div></div></main></div>